def rearrange_array(nums):
    if not nums:
        return []
    result = []
    left, right = 0, len(nums) - 1
    while left <= right:
        if len(result) % 2 == 0:
            result.append(nums[left])
            left += 1
        else:
            result.append(nums[right])
            right -= 1
    return [result[i:i+2] for i in range(0, len(result), 2)]

