def find_permutations(nums):
    if len(nums) == 1:
        return [[nums[0]]]
    result = []
    for i in range(len(nums)):
        current = nums[i]
        rest = nums[:i] + nums[i+1:]
        for p in find_permutations(rest):
            result.append([current] + p)
    return result

